function solve(n, edges, label) {
    const graph = new Array(n);
    for (let i = 0; i < n; i++) {
        graph[i] = [];
    }
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    let maxLen = 1;

    const dfs = (node, visited, path) => {
        const currentLen = path.length;
        if (currentLen > maxLen) {
            maxLen = currentLen;
        }
        for (const neighbor of graph[node]) {
            if (!(visited & (1 << neighbor))) {
                const newVisited = visited | (1 << neighbor);
                const newPath = [...path, label[neighbor]];
                if (isPalindrome(newPath)) {
                    maxLen = Math.max(maxLen, newPath.length);
                }
                dfs(neighbor, newVisited, newPath);
            }
        }
    };

    for (let start = 0; start < n; start++) {
        const initialVisited = 1 << start;
        const initialPath = [label[start]];
        dfs(start, initialVisited, initialPath);
    }

    return maxLen;
}

function isPalindrome(s) {
    let left = 0;
    let right = s.length - 1;
    while (left < right) {
        if (s[left] !== s[right]) return false;
        left++;
        right--;
    }
    return true;
}
